acwing 4700. 何以包邮？水一期
dfs法(test)
算是复习一下，优化一下能拿70
#include&lt;iostream&gt;#include&lt;cstring&gt;using namespace std;const int N = 50;#define inf 0x3f3f3f3fint n, m;int a[N], minn = inf;bool flag[N];void dfs(int now){	if(now &gt;= m)	{		minn = min(minn, now);		return;	}	for(int i = 1; i &lt;= n; i ++)	{		if(flag[i] == false)		{			flag[i] = true;			dfs(now + a[i]);			flag[i] = false;		}	}}int main(){	memset(flag, false, sizeof(flag));	cin &gt;&gt; n &gt;&gt; m;	for(int i = 1; i &lt;= n; i ++)		cin &gt;&gt; a[i];	dfs(0);	cout &lt;&lt; minn &lt;&lt; endl;	return 0;}

状压法#include&lt;iostream&gt;#include&lt;cstring&gt;using namespace std;const int N = 50;const int inf = 1e8;int n, m;int a[N], minn = inf;int main(){		cin &gt;&gt; n &gt;&gt; m;	for(int i = 0; i &lt; n; i ++)		cin &gt;&gt; a[i];	for(int i = 0; i &lt;= 1 &lt;&lt; n; i ++)	{		int sum = 0;		for(int j = 0; j &lt; n; j ++)		{			if(i &gt;&gt; j &amp; 1)			{				sum += a[j];			}		}		if(sum &gt;= m)		{			minn = min(minn, sum);		}	}	cout &lt;&lt; minn &lt;&lt; endl;	return 0;}

动规法类似于01背包，但要求选取的所有物品价值总和越小越好。01背包要求不大于某个数。
则可以转化为选取总和小于sum - x，越大越好。
#include&lt;iostream&gt;#include&lt;cstring&gt;using namespace std;const int N = 50;const int M = 3000010;const int inf = 1e8;int n, m, sum, re;int a[N], minn = inf;int v[M];int main(){		cin &gt;&gt; n &gt;&gt; m;	for(int i = 1; i &lt;= n; i ++)		cin &gt;&gt; a[i], sum += a[i];	re = sum - m;	for(int i = 1; i &lt;= n; i ++)	{		for(int j = re; j &gt;= a[i]; j --)		{			v[j] = max(v[j - a[i]] + a[i], v[j]);		}	}		cout &lt;&lt; sum - v[re] &lt;&lt; endl;	return 0;}
